#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int l, n, m, a[500005], ans;
int check(int x)
{
	int i, s = 0, ans = 0;
	for (int i = 1; i <= n; ++i)
	{
		if (a[i] - s < x)++ans;
		else s = a[i];
	}
	if (l - s < x)++ans;
	return ans <= m;
}
int main(void)
{
	l = read(), n = read(), m = read();
	for (int i = 1; i <= n; ++i)a[i] = read();
	sort(a + 1, a + 1 + n);
	int le = 1, ri = l + 1;
	while (le <= ri)
	{
		int mid = (le + ri) / 2;
		if (check(mid))ans = mid, le = mid + 1;
		else ri = mid - 1;
	}
	write(ans);
	return false;
}
